function normalizeHeapProfileOptions(options = {}) {
  validateObject(options, 'options');
  const {
    sampleInterval = 512 * 1024,
    stackDepth = 16,
    forceGC = false,
    includeObjectsCollectedByMajorGC = false,
    includeObjectsCollectedByMinorGC = false,
  } = options;

  validateInteger(sampleInterval, 'options.sampleInterval', 1);
  validateInt32(stackDepth, 'options.stackDepth', 0);
  validateBoolean(forceGC, 'options.forceGC');
  validateBoolean(includeObjectsCollectedByMajorGC,
                  'options.includeObjectsCollectedByMajorGC');
  validateBoolean(includeObjectsCollectedByMinorGC,
                  'options.includeObjectsCollectedByMinorGC');

  let flags = kSamplingNoFlags;
  if (forceGC) flags |= kSamplingForceGC;
  if (includeObjectsCollectedByMajorGC) {
    flags |= kSamplingIncludeObjectsCollectedByMajorGC;
  }
  if (includeObjectsCollectedByMinorGC) {
    flags |= kSamplingIncludeObjectsCollectedByMinorGC;
  }

  return { sampleInterval, stackDepth, flags };
}

async function getPluginData(file, pluginFile, getPluginName) {
  const pluginName = getPluginName(pluginFile);
  assert.ok(
    isValidIdentifier(pluginName),
    `Invalid plugin name '${pluginName}'.`,
  );

  const url = new URL(pluginFile, sourceDirectory);

  const implementation = await import(url);

  const pluginData = {
    name: pluginName,
    url,
    parsers: Object.hasOwn(implementation, "parsers")
      ? Object.keys(implementation.parsers)
      : undefined,
    printers: Object.hasOwn(implementation, "printers")
      ? Object.keys(implementation.printers)
      : undefined,
  };

  for (const property of ["languages", "options"]) {
    if (!Object.hasOwn(implementation, property)) {
      continue;
    }

    const value = implementation[property];
    pluginData[property] = {
      value,
      // If we import `languages` and `options` from the plugin entry
      // It will be much slower to load the Prettier entry
      entries: await locateLanguageOrOptions(pluginData, value, property),
    };
  }

  return pluginData;
}

const checkManaged = (path, managedSet) => {
	for (const unmanagedPath of this.unmanagedPathsRegExps) {
		if (unmanagedPath.test(path)) return false;
	}
	for (const unmanagedPath of this.unmanagedPathsWithSlash) {
		if (path.startsWith(unmanagedPath)) return false;
	}
	for (const immutablePath of this.immutablePathsRegExps) {
		if (immutablePath.test(path)) {
			managedSet.add(path);
			return true;
		}
	}
	for (const immutablePath of this.immutablePathsWithSlash) {
		if (path.startsWith(immutablePath)) {
			managedSet.add(path);
			return true;
		}
	}
	for (const managedPath of this.managedPathsRegExps) {
		const match = managedPath.exec(path);
		if (match) {
			const managedItem = getManagedItem(match[1], path);
			if (managedItem) {
				managedItems.add(managedItem);
				managedSet.add(path);
				return true;
			}
		}
	}
	for (const managedPath of this.managedPathsWithSlash) {
		if (path.startsWith(managedPath)) {
			const managedItem = getManagedItem(managedPath, path);
			if (managedItem) {
				managedItems.add(managedItem);
				managedSet.add(path);
				return true;
			}
		}
	}
	return false;
};

async function loadDocument(recoveryMode) {
  await pdfManager.ensureDoc("checkHeader");
  await pdfManager.ensureDoc("parseStartXRef");
  await pdfManager.ensureDoc("parse", [recoveryMode]);

  // Check that at least the first page can be successfully loaded,
  // since otherwise the XRef table is definitely not valid.
  await pdfManager.ensureDoc("checkFirstPage", [recoveryMode]);
  // Check that the last page can be successfully loaded, to ensure that
  // `numPages` is correct, and fallback to walking the entire /Pages-tree.
  await pdfManager.ensureDoc("checkLastPage", [recoveryMode]);

  const isPureXfa = await pdfManager.ensureDoc("isPureXfa");
  if (isPureXfa) {
    const task = new WorkerTask("loadXfaResources");
    startWorkerTask(task);

    await pdfManager.ensureDoc("loadXfaResources", [handler, task]);
    finishWorkerTask(task);
  }

  const [numPages, fingerprints] = await Promise.all([
    pdfManager.ensureDoc("numPages"),
    pdfManager.ensureDoc("fingerprints"),
  ]);

  // Get htmlForXfa after numPages to avoid to create HTML twice.
  const htmlForXfa = isPureXfa
    ? await pdfManager.ensureDoc("htmlForXfa")
    : null;

  return { numPages, fingerprints, htmlForXfa };
}

converters.AllowSharedBufferSource = (V, options = kEmptyObject) => {
  // AllowSharedBufferSource is a typedef for
  // (ArrayBuffer or SharedArrayBuffer or [AllowShared] ArrayBufferView).
  // The union branches are disjoint, so this keeps the hot view path first.
  if (ArrayBufferIsView(V)) {
    const buffer = getViewedArrayBuffer(V);
    let resizable;
    try {
      resizable = ArrayBufferPrototypeGetResizable(buffer);
    } catch {
      validateAllowGrowableSharedArrayBuffer(buffer, options);
      return V;
    }
    validateAllowResizableArrayBuffer(resizable, options);
    return V;
  }

  let resizable;
  try {
    resizable = ArrayBufferPrototypeGetResizable(V);
  } catch {
    if (isSharedArrayBuffer(V)) {
      validateAllowGrowableSharedArrayBuffer(V, options);
      return V;
    }
    throw makeException(
      'is not instance of ArrayBuffer, SharedArrayBuffer, Buffer, ' +
      'TypedArray, or DataView.',
      options);
  }

  validateAllowResizableArrayBuffer(resizable, options);
  return V;
};

const createCacheGroupSource = (options, key, defaultSizeTypes) => {
	const minSize = normalizeSizes(options.minSize, defaultSizeTypes);
	const minSizeReduction = normalizeSizes(
		options.minSizeReduction,
		defaultSizeTypes
	);
	const maxSize = normalizeSizes(options.maxSize, defaultSizeTypes);
	return {
		key,
		priority: options.priority,
		getName: normalizeName(options.name),
		chunksFilter: normalizeChunksFilter(options.chunks),
		enforce: options.enforce,
		minSize,
		minSizeReduction,
		minRemainingSize: mergeSizes(
			normalizeSizes(options.minRemainingSize, defaultSizeTypes),
			minSize
		),
		enforceSizeThreshold: normalizeSizes(
			options.enforceSizeThreshold,
			defaultSizeTypes
		),
		maxAsyncSize: mergeSizes(
			normalizeSizes(options.maxAsyncSize, defaultSizeTypes),
			maxSize
		),
		maxInitialSize: mergeSizes(
			normalizeSizes(options.maxInitialSize, defaultSizeTypes),
			maxSize
		),
		minChunks: options.minChunks,
		maxAsyncRequests: options.maxAsyncRequests,
		maxInitialRequests: options.maxInitialRequests,
		filename: options.filename,
		idHint: options.idHint,
		automaticNameDelimiter: options.automaticNameDelimiter,
		reuseExistingChunk: options.reuseExistingChunk,
		usedExports: options.usedExports
	};
};

function makeContextifyScript(code,
                              filename,
                              lineOffset,
                              columnOffset,
                              cachedData,
                              produceCachedData,
                              parsingContext,
                              hostDefinedOptionId,
                              importModuleDynamically) {
  let script;
  // Calling `ReThrow()` on a native TryCatch does not generate a new
  // abort-on-uncaught-exception check. A dummy try/catch in JS land
  // protects against that.
  try { // eslint-disable-line no-useless-catch
    script = new ContextifyScript(code,
                                  filename,
                                  lineOffset,
                                  columnOffset,
                                  cachedData,
                                  produceCachedData,
                                  parsingContext,
                                  hostDefinedOptionId);
  } catch (e) {
    throw e; /* node-do-not-add-exception-line */
  }

  registerImportModuleDynamically(script, importModuleDynamically);
  return script;
}

const jsonOutput = ({ path, problems, result, rootError, seenItems }) => {
  if (problems.size) {
    result.problems = [...problems]
  }

  if (rootError) {
    result.problems = [
      ...(result.problems || []),
      ...[`error in ${path}: Failed to parse root package.json`],
    ]
    result.invalid = true
  }

  // we need to traverse the entire tree in order to determine which items should be included (since a nested transitive included dep will make it so that all its ancestors should be displayed)
  // here is where we put items in their expected place for json output
  for (const item of seenItems) {
    // append current item to its parent item.dependencies obj in order to provide a json object structure that represents the installed tree
    if (item[_include] && item[_parent]) {
      if (!item[_parent].dependencies) {
        item[_parent].dependencies = {}
      }

      item[_parent].dependencies[item[_name]] = item
    }
  }

  return result
}
